class Solution:
    def largestRectangleArea(self, heights):
        stack = []
        best = 0
        for i, height in enumerate(heights + [0]):
            while stack and height < heights[stack[-1]]:
                h = heights[stack.pop()]
                left = stack[-1] if stack else -1
                best = max(best, h * (i - left - 1))
            stack.append(i)
        return best
